import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { resolveSafePath } from './safe-path.mjs';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const ROOT = path.resolve(__dirname, '..');

const README_START_MARKER =
    '<!-- log-codes:start — DO NOT EDIT: auto-generated by `npm run logs:list` -->';
const README_END_MARKER =
    '<!-- log-codes:end — DO NOT EDIT: auto-generated by `npm run logs:list` -->';

// Matches logger.(error|warn)('CODE', 'message') with single/double/backtick-quoted strings.
// Handles multi-line calls. For template literals with interpolation the message is
// captured up to the first `${` (shown as a truncated description with … in the README).
const LOG_CALL_RE = /logger\.(error|warn)\(\s*['"]([A-Z_]+)['"]\s*,\s*['"`]([^'"`$\n]+)/gs;

function* walkSrc(dir) {
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
        const full = resolveSafePath(entry.name, dir);
        if (entry.isDirectory()) {
            yield* walkSrc(full);
        } else if (/\.(ts|vue)$/.test(entry.name) && !entry.name.includes('.spec.')) {
            yield full;
        }
    }
}

export function scanLogCodes(srcDir, baseDir = ROOT) {
    const resolvedBase = path.resolve(baseDir);
    const resolved = path.resolve(srcDir);
    if (resolved !== resolvedBase && !resolved.startsWith(resolvedBase + path.sep)) {
        throw new Error(`Path traversal detected: "${srcDir}" is outside "${baseDir}"`);
    }
    /** @type {Map<string, { level: string; code: string; message: string; file: string }>} */
    const byCode = new Map();

    for (const file of walkSrc(srcDir)) {
        const content = fs.readFileSync(file, 'utf-8');
        for (const match of content.matchAll(LOG_CALL_RE)) {
            const [, level, code, message] = match;
            if (!byCode.has(code)) {
                // When the original string was a template literal with ${...}, the regex
                // stops before the $, leaving a trailing space — add … to signal truncation.
                const trimmed = message.trimEnd();
                const display = trimmed !== message ? trimmed + '…' : trimmed;
                byCode.set(code, {
                    level,
                    code,
                    message: display,
                    file: path.relative(ROOT, file),
                });
            }
        }
    }

    return [...byCode.values()].sort((a, b) => {
        if (a.level !== b.level) return a.level < b.level ? -1 : 1;
        return a.code.localeCompare(b.code);
    });
}

export function buildMarkdownSection(entries) {
    const errors = entries.filter((e) => e.level === 'error');
    const warns = entries.filter((e) => e.level === 'warn');

    const table = (rows) => {
        const lines = ['| Code | Description |', '| :--- | :---------- |'];
        for (const { code, message } of rows) {
            lines.push(`| \`${code}\` | ${message} |`);
        }
        return lines.join('\n');
    };

    const parts = [];

    if (errors.length) {
        parts.push('### Error codes\n\n' + table(errors));
    }
    if (warns.length) {
        parts.push('### Warning codes\n\n' + table(warns));
    }

    return (
        `## Error logging\n\n` +
        `The SDK emits structured log entries via the [\`onLog\`](#error-logging) callback. ` +
        `Subscribe to receive all log events and filter by \`code\` for programmatic handling.\n\n` +
        parts.join('\n\n')
    );
}

export function updateReadme(readmePath, section, baseDir = ROOT) {
    resolveSafePath(readmePath, baseDir);
    const content = fs.readFileSync(readmePath, 'utf-8');

    const block = `${README_START_MARKER}\n${section}\n${README_END_MARKER}`;

    if (content.includes(README_START_MARKER)) {
        const updated = content.replace(
            new RegExp(`${README_START_MARKER}[\\s\\S]*?${README_END_MARKER}`),
            block,
        );
        fs.writeFileSync(readmePath, updated, 'utf-8');
        return 'updated';
    }

    fs.writeFileSync(readmePath, `${content.trimEnd()}\n\n${block}\n`, 'utf-8');
    return 'appended';
}

if (process.argv[1] === __filename) {
    const srcDir = path.join(ROOT, 'src');
    const readmePath = path.join(ROOT, 'README.md');

    const entries = scanLogCodes(srcDir);
    const section = buildMarkdownSection(entries);
    const result = updateReadme(readmePath, section);

    const errorCount = entries.filter((e) => e.level === 'error').length;
    const warnCount = entries.filter((e) => e.level === 'warn').length;

    console.log(`✅ README ${result}: ${errorCount} error code(s), ${warnCount} warning code(s).`);
}
